from flask import Flask, jsonify, request
from itsdangerous import TimedJSONWebSignatureSerializer as Serializer

app = Flask(__name__)

# Set the secret key for signing and verifying tokens
app.config['SECRET_KEY'] = 'your-secret-key'

@app.route('/login', methods=['POST'])
def login():
    # Get the username and password from the request body
    username = request.json['username']
    password = request.json['password']

    # Check if the user exists in the database
    if not check_user(username, password):
        return jsonify({'error': 'Invalid credentials'}), 401

    # Create a token for the user
    serializer = Serializer(app.config['SECRET_KEY'], expires_in=3600)
    token = serializer.dumps({'username': username})

    # Return the token to the client
    return jsonify({'token': token.decode('utf-8')}), 200

@app.route('/protected', methods=['GET'])
def protected():
    # Get the token from the request headers
    token = request.headers.get('Authorization')

    # Check if the token is valid
    serializer = Serializer(app.config['SECRET_KEY'], expires_in=3600)
    try:
        data = serializer.loads(token)
    except SignatureExpired:
        return jsonify({'error': 'Token has expired'}), 401
    except BadSignature:
        return jsonify({'error': 'Invalid token'}), 401

    # Get the username from the token data
    username = data['username']

    # Return a protected resource for the user
    return jsonify({'message': f'Hello, {username}!'}), 200

